private void setTemplateName(String apname , String path , int sheetIndex , String templateId , String templateName) throws Exception{
    NUIForm form = AppManager.getFormPage(apname, path, sheetIndex);
    if(form == null) throw new Exception("Sheet " + apname + path + "/" + sheetIndex + " not found");
    String[] templateSecs = form.getTemplates().get(templateId);
    String[] updatedTemplateSecs = getSecs(templateSecs);
    if(updatedTemplateSecs == null) throw new Exception("Template format incorrect");
    updatedTemplateSecs[0] = templateName;
    form.setTemplate(templateId, updatedTemplateSecs);
    form.saveFile(apname,path,true);

    NUIForm listlingPageForm = AppManager.getListingPage(apname, path, sheetIndex);
    if(listlingPageForm == null) throw new Exception("Sheet " + apname + path + "/" + sheetIndex + " not found");
    String[] listlingTemplateSecs = listlingPageForm.getTemplates().get(templateId);
    String[] listlingUpdatedTemplateSecs = getSecs(listlingTemplateSecs);
    if(listlingUpdatedTemplateSecs == null) throw new Exception("Template format incorrect");
    listlingUpdatedTemplateSecs[0] = templateName;
    listlingPageForm.setTemplate(templateId, listlingUpdatedTemplateSecs);
    listlingPageForm.saveFile(apname,path,true);
}

private String[] getSecs(String[] templateSecs) {
    String templateName = templateSecs.length > 0? templateSecs[0]: null; // must
    String fileName = templateSecs.length > 1? templateSecs[1]: null; // must
    if(templateName == null || fileName == null) {
        return null;
    }
    String ifListingPage = templateSecs.length > 2? templateSecs[2]: "false";
    String displayButton = templateSecs.length > 3? templateSecs[3]: "true";
    String accessRights = templateSecs.length > 4? templateSecs[4]: "";
    String ifMaintainImgAspectRatio = templateSecs.length > 5? templateSecs[5]: "false";
    String exportFileNameRefDomain = templateSecs.length > 6? templateSecs[6] : "";
    return new String[] {
            templateName, fileName, ifListingPage, displayButton, accessRights, ifMaintainImgAspectRatio, exportFileNameRefDomain
    };
}

